mapper.select:
select c.customer_id AS id, c.customer_name AS customerName, c.age, c.gender, c.tel, r.building AS buildingNumber, r.room_no AS roomNumber, b.bed_no AS bedNumber, n.nursing_level_name AS nursingLevel from customer c left join bed b on c.bed_id = b.bed_id left join nursing_level n on c.nursing_level_id = n.nursing_level_id left join room r on b.room_id = r.room_id where c.user_id=#{caregiverId} and c.del_flag = '0'
and c.customer_name like concat('%', #{customerName}, '%')
ORDER BY c.customer_id DESC LIMIT #{pageStart}, #{pageSize}

mapper.update:
UPDATE user
SET password = #{password}
WHERE email = #{email}
  AND del_flag = '0'

UPDATE user
SET img = #{upload}
WHERE user_id = #{userId}
  AND del_flag = '0'
